### E2E Tests
```typescript
// tailwind-e2e.spec.ts
test.describe("Tailwind Migration E2E", () => {
  test("responsive layout works at all breakpoints", async ({ page }) => {
    const breakpoints = [
      { width: 320, name: "mobile" },
      { width: 768, name: "tablet" },
      { width: 1024, name: "desktop" },
      { width: 1440, name: "large" },
    ];

    for (const { width, name } of breakpoints) {
      await page.setViewportSize({ width, height: 800 });
      await page.goto("/");

      // Verify layout doesn't break
      await expect(page.locator("main")).toBeVisible();
      await expect(page.locator("nav")).toBeVisible();

      // Take screenshot for manual review
      await page.screenshot({ path: `screenshots/responsive-${name}.png` });
    }
  });

  test("hover and focus states work correctly", async ({ page }) => {
    await page.goto("/");

    const button = page.locator("button").first();
    const initialBg = await button.evaluate(el => 
      getComputedStyle(el).backgroundColor
    );

    await button.hover();
    const hoverBg = await button.evaluate(el => 
      getComputedStyle(el).backgroundColor
    );

    expect(hoverBg).not.toBe(initialBg);
  });

  test("animations work correctly", async ({ page }) => {
    await page.goto("/");

    // Open a modal
    await page.click('[data-testid="open-modal"]');

    // Verify animation class is applied
    const modal = page.locator('[data-testid="modal"]');
    await expect(modal).toHaveClass(/animate/);
  });

  test("no CSS conflicts or specificity issues", async ({ page }) => {
    const errors: string[] = [];
    page.on("console", msg => {
      if (msg.text().includes("CSS") || msg.text().includes("style")) {
        errors.push(msg.text());
      }
    });

    await page.goto("/");
    await page.waitForLoadState("networkidle");

    // Navigate through all pages
    for (const path of ["/fleet", "/agents", "/pipelines", "/settings"]) {
      await page.goto(path);
    }

    expect(errors).toHaveLength(0);
  });
});
```

