    const stats = await getBuildStats();
    const cssAssets = stats.assets.filter(a => a.name.endsWith(".css"));
    const totalCssSize = cssAssets.reduce((sum, a) => sum + a.size, 0);

    // Original index.css was ~50kb, target is <25kb
