    it("should enforce severity enum values", async () => {
      // Test valid severities
      for (const severity of ["critical", "high", "medium", "low"]) {
        const id = `dcg_severity_${severity}`;
        await db.insert(dcgBlocks).values({
          id,
          command: "test",
          pack: "test",
          pattern: "test",
          ruleId: "test:test",
          severity,
          reason: "test",
        });
        logger.debug({ severity, id }, "Tested valid severity");
      }
    });
  });

  describe("dcgAllowlist table", () => {
    it("should have renamed columns (addedBy, addedAt)", async () => {
      const columns = getTableColumns(dcgAllowlist);
      expect(columns).toContain("addedBy");
      expect(columns).toContain("addedAt");
      expect(columns).toContain("reason");
      expect(columns).toContain("condition");
      expect(columns).not.toContain("approvedBy"); // Old name
      expect(columns).not.toContain("createdAt");   // Old name for this table
      logger.info({ columns, testName: "allowlist_columns" }, "Verified allowlist columns");
    });

    it("should enforce unique ruleId constraint", async () => {
      await db.insert(dcgAllowlist).values({
        id: "allow_1",
        ruleId: "unique-rule-id",
        pattern: "test",
        reason: "test reason",
        addedBy: "test-user",
      });

      await expect(
        db.insert(dcgAllowlist).values({
          id: "allow_2",
          ruleId: "unique-rule-id", // Duplicate
          pattern: "test2",
          reason: "test reason 2",
          addedBy: "test-user",
        })
      ).rejects.toThrow();

      logger.info({ testName: "unique_constraint" }, "Unique ruleId constraint enforced");
    });
  });

  describe("indexes", () => {
    it("should have indexes on frequently queried columns", async () => {
      const indexes = await getTableIndexes(db, "dcg_blocks");
      expect(indexes).toContainEqual(expect.objectContaining({ name: "dcg_blocks_agent_idx" }));
      expect(indexes).toContainEqual(expect.objectContaining({ name: "dcg_blocks_pack_idx" }));
      expect(indexes).toContainEqual(expect.objectContaining({ name: "dcg_blocks_severity_idx" }));
      expect(indexes).toContainEqual(expect.objectContaining({ name: "dcg_blocks_created_at_idx" }));
      logger.info({ indexes, testName: "index_verification" }, "All indexes present");
    });
  });
});
```

### Integration Tests (`apps/gateway/tests/integration/dcg-schema.test.ts`)

```typescript
describe("DCG Schema Integration", () => {
  it("should migrate existing data without loss", async () => {
    // This test requires setup with pre-migration data
    const preCount = await db.select({ count: sql`count(*)` }).from(dcgBlocks);
    logger.info({ preCount, testName: "migration_data_preservation" }, "Pre-migration count");

    // Migration would have run during test setup
    const postCount = await db.select({ count: sql`count(*)` }).from(dcgBlocks);
    expect(postCount[0].count).toBe(preCount[0].count);
    logger.info({ postCount, testName: "migration_data_preservation" }, "Post-migration count matches");
  });

  it("should support service layer operations after migration", async () => {
    // Test ingestBlockEvent with new schema
    const event = await ingestBlockEvent({
      command: "dangerous command",
      pack: "core.filesystem",
      pattern: "rm.*-rf",
      ruleId: "core.filesystem:rm-rf",
      severity: "critical",
      reason: "Recursive delete blocked",
      agentId: "agent_test",
      contextClassification: "executed",
    });

    expect(event.id).toMatch(/^dcg_/);
    expect(event.pack).toBe("core.filesystem");
    logger.info({ 
      eventId: event.id, 
      pack: event.pack,
      correlationId: getCorrelationId(),
      testName: "service_integration" 
    }, "Service layer works with new schema");
  });

  it("should handle concurrent inserts without deadlock", async () => {
    const promises = Array.from({ length: 10 }, (_, i) => 
      ingestBlockEvent({
        command: `concurrent command ${i}`,
        pack: "test.concurrent",
        pattern: "test",
        ruleId: `test:concurrent-${i}`,
        severity: "low",
        reason: "Concurrent test",
      })
    );

    const results = await Promise.all(promises);
    expect(results).toHaveLength(10);
    logger.info({ 
      resultCount: results.length, 
      ids: results.map(r => r.id),
      testName: "concurrent_insert" 
    }, "Concurrent inserts succeeded");
  });
});
```

### Logging Requirements

All tests MUST log:
1. **correlationId** - For request tracing
2. **testName** - Identifier for the specific test
3. **Input data** - What was passed to the operation
4. **Output data** - What was returned
5. **Timing** - Duration of database operations

Example log format:
```json
{
  "level": "info",
  "time": "2026-01-11T12:34:56.789Z",
  "testName": "insert_retrieve",
  "correlationId": "test-abc123",
  "operation": "db.insert",
  "table": "dcg_blocks",
  "duration_ms": 15,
  "rowsAffected": 1,
  "msg": "Insert operation completed"
}
```

## Acceptance Criteria

- [ ] dcgBlocks has all columns needed by DCGBlockEvent interface
- [ ] dcgAllowlist has all columns needed by DCGAllowlistEntry interface  
- [ ] Field names match between schema and service (no mapping layer needed)
- [ ] Migration runs successfully on existing database
- [ ] Migration preserves existing data (no data loss)
- [ ] All DCG service tests pass with new schema
- [ ] Indexes exist for common query patterns (agent, pack, severity, date)
- [ ] markFalsePositive correctly updates the updatedAt field
- [ ] All unit tests pass with comprehensive logging
- [ ] All integration tests pass with comprehensive logging

## Risk Mitigation

1. **Backup before migration**: Always backup database before running migration
2. **Test migration on copy**: Run migration on copy of production DB first
3. **Reversible migration**: Define down migration for rollback capability
4. **Staged rollout**: Deploy schema changes before code changes that depend on them
